import React, { useState } from "react";
import { NavLink } from "react-router-dom";
import "./nav.css";

const menus = [
  { label: "Home", href: "/" },
  { label: "Teachers", href: "/teachers" },
  { label: "Holidays", href: "/holidays" },
  { label: "Contact Us", href: "/contacts" },
];

function Navbar() {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <nav className="sticky top-0 left-0 z-50 bg-white shadow-md">
      <div className="flex justify-between items-center px-6 py-3">

        {/* Logo */}
        <div className="flex items-center gap-3">
          <img src="./Photo/logo.webp" width="50" alt="Logo" />
          <h1 className="text-xl font-bold">CodingSchool</h1>
        </div>

        {/* Desktop Menu */}
        <ul className="hidden md:flex list-none items-center gap-6">
          {menus.map((item) => (
            <li key={item.href}>
              <NavLink
                to={item.href}
                style={({ isActive }) => ({
                  textDecoration: "none",
                  paddingBottom: "4px",
                  fontSize: 17,
                  color: isActive ? "#1E3A8A" : "#323232",
                  borderBottom: isActive ? "2px solid #1E3A8A" : "none",
                  fontWeight: isActive ? "700" : "500",
                })}
              >
                {item.label}
              </NavLink>
            </li>
          ))}
        </ul>

        {/* Hamburger Button — shown only on mobile */}
        <button
          className="md:hidden text-2xl text-gray-700"
          onClick={() => setIsOpen(!isOpen)}
          aria-label="Toggle navigation menu"
        >
          <i className={isOpen ? "ri-close-line" : "ri-menu-line"}></i>
        </button>
      </div>

      {/* Mobile Dropdown — conditionally rendered based on isOpen */}
      {isOpen && (
        <ul className="md:hidden list-none flex flex-col gap-4 px-6 pb-5 border-t pt-3">
          {menus.map((item) => (
            <li key={item.href}>
              <NavLink
                to={item.href}
                onClick={() => setIsOpen(false)}
                style={({ isActive }) => ({
                  textDecoration: "none",
                  fontSize: 16,
                  color: isActive ? "#1E3A8A" : "#323232",
                  fontWeight: isActive ? "700" : "500",
                })}
              >
                {item.label}
              </NavLink>
            </li>
          ))}
        </ul>
      )}
    </nav>
  );
}

export default Navbar;
